="form-control"><option value=""><?=sd_h('common_all', 'All');?></option><?php foreach($currencies as $c){ ?><option value="<?=htmlspecialchars($c->currency,ENT_QUOTES,'UTF-8');?>"><?=htmlspecialchars($c->currency,ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div><label class="control-label col-lg-1">Convert</label><div class="col-lg-2"><select id="filter_conversion_status" class="form-control"><option value=""><?=sd_h('common_all', 'All');?></option><option value="CONVERTED">Converted</option><option value="NOT_CONVERTED">Not Converted</option></select></div><div class="col-lg-2"><input id="filter_keyword" class="form-control" placeholder="Quotation, customer, subject"></div></div><div class="form-group"><div class="col-lg-offset-2 col-lg-10"><button id="btn_filter_sqr" class="btn btn-primary"><i class="fa fa-filter"></i> <?=sd_h('common_filter', 'Filter');?></button> <button id="btn_reset_sqr" class="btn btn-default"><i class="fa fa-refresh"></i> <?=sd_h('common_reset', 'Reset');?></button> <button id="btn_excel_sqr" class="btn btn-success"><i class="fa fa-file-excel-o"></i> <?=sd_h('common_export_excel', 'Export Excel');?></button></div></div></form></div></div>
