<script>
function sqrError(m){$('.isi_warning_delete').text(m||<?=sd_js('sales_quotation_report_process_failed', 'Sales Quotation Report failed to process.');?>);$('.error_data_delete').fadeIn();}
function sqrFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),customer_id:$('#filter_customer_id').val(),status:$('#filter_status').val(),sales_person:$('#filter_sales_person').val(),currency:$('#filter_currency').val(),conversion_status:$('#filter_conversion_status').val(),keyword:$('#filter_keyword').val()};}
function sqrQuery(){return $.param(sqrFilters());}
$(function(){if($.fn.datepicker){$('.sqr-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_customer_id,#filter_status,#filter_sales_person,#filter_currency,#filter_conversion_status').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_sales_quotation_report').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=sd_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'76px',targets:1}],ajax:{url:'<?=base_admin();?>modul/sales_quotation_report/sales_quotation_report_data.php',type:'post',data:function(d){$.extend(d,sqrFilters());},error:function(xhr){console.log(xhr.responseText);sqrError(<?=sd_js('sales_quotation_report_load_failed', 'Sales Quotation Report data failed to load.');?>);}}});
$('#btn_filter_sqr').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_sqr').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_customer_id,#filter_status,#filter_sales_person,#filter_currency,#filter_conversion_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_sqr').click(function(){window.location='<?=base_admin();?>modul/sales_quotation_report/sales_quotation_report_action.php?act=excel&'+sqrQuery();});
$(document).on('click','.btn-sqr-detail',function(){$.post('<?=base_admin();?>modul/sales_quotation_report/sales_quotation_report_action.php?act=detail',{id:$(this).data('id')},function(html){$('#sqr_detail_body').html(html);$('#modal_detail_sqr').modal('show');}).fail(function(){sqrError('Detail gagal dibuka.');});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
